const DOP_QUESTIONS = [

  { cat: "sdlc-automation", q: "Which AWS service allows you to automate the entire continuous integration and continuous deployment (CI/CD) workflow?", options: ["A. AWS CodePipeline", "B. AWS CodeBuild", "C. AWS CodeDeploy", "D. AWS CodeCommit"], answer: 0, explain: "CodePipeline is the service that orchestrates the entire CI/CD workflow, integrating with CodeBuild, CodeDeploy, and other services." },
  { cat: "sdlc-automation", q: "You need to compile source code and run unit tests. Which service should you use?", options: ["A. AWS CodePipeline", "B. AWS CodeBuild", "C. AWS CodeDeploy", "D. AWS CloudFormation"], answer: 1, explain: "CodeBuild is a fully managed service that compiles source code, runs tests, and produces ready-to-deploy software packages." },
  { cat: "sdlc-automation", q: "What is the primary purpose of AWS CodeDeploy?", options: ["A. To compile source code", "B. To automate application deployments to on-premises servers and AWS compute services", "C. To store source code", "D. To monitor application performance"], answer: 2, explain: "CodeDeploy automates application deployments to various compute services including EC2 instances, on-premises servers, and Lambda." },
  { cat: "sdlc-automation", q: "Which deployment strategy in CodeDeploy terminates old instances after new instances are fully deployed?", options: ["A. In-place deployment", "B. Blue/green deployment", "C. Canary deployment", "D. Rolling deployment"], answer: 3, explain: "Blue/green deployment maintains two identical production environments, allowing old instances to be terminated after validation." },
  { cat: "sdlc-automation", q: "What is the benefit of using canary deployments?", options: ["A. Faster deployment time", "B. Minimal traffic exposure during deployment", "C. Reduces deployment cost", "D. Allows instant rollback"], answer: 0, explain: "Canary deployments shift a small percentage of traffic to new versions first, minimizing the blast radius of issues." },
  { cat: "sdlc-automation", q: "Which service is used to store and manage Git repositories on AWS?", options: ["A. AWS CodeDeploy", "B. AWS CodeBuild", "C. AWS CodeCommit", "D. AWS CodePipeline"], answer: 1, explain: "CodeCommit is AWS's Git repository service, providing version control capabilities similar to GitHub." },
  { cat: "sdlc-automation", q: "What does SAM stand for in the AWS ecosystem?", options: ["A. Server Application Module", "B. Serverless Application Model", "C. Service Automation Manager", "D. Software Asset Management"], answer: 2, explain: "SAM (Serverless Application Model) is an open-source framework for building serverless applications on AWS." },
  { cat: "sdlc-automation", q: "Which AWS service allows you to define infrastructure as code using Python, TypeScript, or Java?", options: ["A. AWS SAM", "B. AWS CloudFormation", "C. AWS CDK", "D. AWS CodeBuild"], answer: 3, explain: "AWS CDK (Cloud Development Kit) allows you to define cloud infrastructure using programming languages like Python and TypeScript." },
  { cat: "sdlc-automation", q: "What is an artifact in the context of AWS CodePipeline?", options: ["A. A deployment configuration file", "B. Output files from build or test stages", "C. A version control branch", "D. A CloudFormation template"], answer: 0, explain: "Artifacts are output files from pipeline stages, such as compiled binaries or test reports, stored in S3." },
  { cat: "sdlc-automation", q: "Where should build artifacts be stored in a CodePipeline?", options: ["A. EC2 instances", "B. Amazon S3", "C. Amazon DynamoDB", "D. Amazon ElastiCache"], answer: 1, explain: "CodePipeline stores artifacts in an S3 bucket, allowing stages to retrieve and use artifacts from previous stages." },
  { cat: "sdlc-automation", q: "Which GitHub Actions integration with AWS allows for CI/CD workflows?", options: ["A. AWS CodePipeline GitHub connector", "B. AWS CodeBuild GitHub integration", "C. AWS CodeDeploy GitHub plugin", "D. All of the above"], answer: 3, explain: "GitHub Actions can integrate with multiple AWS services to enable CI/CD workflows across the AWS ecosystem." },
  { cat: "sdlc-automation", q: "What is the primary advantage of using CodePipeline over manual deployments?", options: ["A. Lower AWS API call costs", "B. Automated, repeatable, and reliable deployment process", "C. Reduced team training requirements", "D. Faster compilation times"], answer: 0, explain: "CodePipeline automates and standardizes deployments, ensuring consistency and reducing human error across releases." },
  { cat: "sdlc-automation", q: "How does CodeBuild determine what commands to execute?", options: ["A. Through IAM policies", "B. From environment variables only", "C. From a buildspec.yml file in the source repository", "D. From CloudFormation parameters"], answer: 2, explain: "CodeBuild reads instructions from a buildspec.yml file in the source code to determine the build steps." },
  { cat: "sdlc-automation", q: "Which deployment approach allows you to gradually shift traffic from old to new instances?", options: ["A. All-at-once deployment", "B. Blue/green deployment", "C. Linear deployment", "D. Instant deployment"], answer: 1, explain: "Blue/green deployment enables gradual traffic shifting by maintaining separate environments and controlling the cutover." },
  { cat: "sdlc-automation", q: "What is the role of AppSpec in CodeDeploy?", options: ["A. Defines the CodeBuild configuration", "B. Specifies deployment actions and lifecycle event hooks", "C. Configures IAM permissions", "D. Sets up the CI/CD pipeline stages"], answer: 0, explain: "The AppSpec file defines deployment actions, lifecycle events, and how CodeDeploy should deploy your application." },
  { cat: "sdlc-automation", q: "In a CodePipeline, what happens when a stage fails?", options: ["A. The entire pipeline is deleted", "B. The pipeline stops and waits for manual approval", "C. The next stage begins immediately", "D. The pipeline automatically rolls back to the previous version"], answer: 1, explain: "When a stage fails, the pipeline stops execution and requires either manual intervention or automatic retry." },
  { cat: "sdlc-automation", q: "Which CDK construct represents an EC2 instance in your infrastructure?", options: ["A. Instance", "B. EC2Instance", "C. ServerInstance", "D. ComputeInstance"], answer: 0, explain: "In AWS CDK, the Instance construct represents an EC2 instance and allows programmatic configuration." },
  { cat: "sdlc-automation", q: "What is the purpose of a CodeCommit pull request?", options: ["A. To compile code", "B. To request code review before merging to a branch", "C. To deploy code", "D. To monitor code performance"], answer: 1, explain: "Pull requests in CodeCommit enable code review and collaborative development before merging changes." },
  { cat: "sdlc-automation", q: "How can you trigger a CodePipeline execution automatically?", options: ["A. Manually through the AWS Console", "B. Through an EventBridge rule on CodeCommit push events", "C. Only through AWS CLI", "D. Through CloudFormation stack updates"], answer: 0, explain: "CodePipeline can be automatically triggered by CodeCommit pushes using EventBridge or CodePipeline's native polling." },
  { cat: "sdlc-automation", q: "What does the CodeDeploy agent do?", options: ["A. Compiles source code", "B. Installs dependencies and runs deployment commands on instances", "C. Monitors application health", "D. Manages CI/CD pipelines"], answer: 1, explain: "The CodeDeploy agent is installed on instances and executes deployment instructions from AppSpec files." },
  { cat: "sdlc-automation", q: "Which strategy is best for deploying to a large fleet of instances with minimal downtime?", options: ["A. All-at-once", "B. In-place rolling deployment", "C. One-at-a-time", "D. Manual deployment"], answer: 0, explain: "Rolling deployments update instances in batches, maintaining service availability while minimizing downtime." },
  { cat: "sdlc-automation", q: "What is a primary advantage of Infrastructure as Code (IaC)?", options: ["A. Reduces development time", "B. Enables version control and reproducible infrastructure", "C. Increases infrastructure cost", "D. Simplifies manual configuration"], answer: 1, explain: "IaC allows infrastructure to be version-controlled, tested, and reproduced consistently across environments." },
  { cat: "sdlc-automation", q: "Which service integrates with CodePipeline to perform automated compliance checks?", options: ["A. AWS Config", "B. AWS Systems Manager", "C. AWS CloudTrail", "D. AWS Organizations"], answer: 0, explain: "AWS Config can be integrated into CodePipeline to validate infrastructure compliance before deployment." },
  { cat: "sdlc-automation", q: "What is the CodeBuild cache feature used for?", options: ["A. To store build logs", "B. To speed up subsequent builds by reusing dependencies", "C. To monitor build performance", "D. To control access to build artifacts"], answer: 1, explain: "CodeBuild caching stores dependencies locally, reducing build time for subsequent builds with the same dependencies." },
  { cat: "sdlc-automation", q: "How do you store secrets in a CodeBuild project?", options: ["A. In plaintext in buildspec.yml", "B. In environment variables", "C. In AWS Systems Manager Parameter Store or AWS Secrets Manager", "D. In CodeCommit repositories"], answer: 2, explain: "Secrets should be stored in Parameter Store or Secrets Manager and referenced in CodeBuild, never in plaintext." },
  { cat: "sdlc-automation", q: "Which CodeDeploy deployment target is NOT supported?", options: ["A. EC2 instances", "B. On-premises servers", "C. Lambda functions", "D. RDS databases"], answer: 3, explain: "CodeDeploy supports EC2, on-premises servers, and Lambda, but not RDS. RDS uses different deployment mechanisms." },
  { cat: "sdlc-automation", q: "What is the purpose of the CodeDeploy lifecycle event 'ApplicationStart'?", options: ["A. To run tests after deployment", "B. To start the application after deployment is complete", "C. To backup the previous version", "D. To validate the deployment"], answer: 1, explain: "The ApplicationStart event runs scripts to start the application after the deployment files have been copied." },
  { cat: "sdlc-automation", q: "How can you prevent concurrent CodePipeline executions?", options: ["A. Set the execution mode to Sequential", "B. Use IAM policies", "C. Configure CloudWatch alarms", "D. It's not possible in CodePipeline"], answer: 0, explain: "CodePipeline allows you to set execution mode to Sequential, preventing parallel pipeline executions." },
  { cat: "sdlc-automation", q: "Which AWS service provides automated testing capabilities within a pipeline?", options: ["A. AWS CodeBuild", "B. AWS CodeDeploy", "C. AWS CloudFormation", "D. AWS Lambda"], answer: 0, explain: "CodeBuild can run test suites as part of the build process within a CodePipeline." },
  { cat: "sdlc-automation", q: "What does the SAM CLI tool 'sam build' command do?", options: ["A. Compiles the application locally", "B. Prepares the SAM template for deployment", "C. Validates IAM permissions", "D. Uploads artifacts to S3"], answer: 1, explain: "sam build processes the SAM template and prepares it for local testing or deployment to AWS." },
  { cat: "sdlc-automation", q: "How do you define a Lambda function in CDK?", options: ["A. Using the Function construct", "B. Using the Lambda construct", "C. Using the ServerlessFunction construct", "D. Using the Compute construct"], answer: 0, explain: "The Function construct in AWS CDK is used to define and configure Lambda functions." },
  { cat: "sdlc-automation", q: "Which deployment strategy in CodeDeploy is recommended for critical production deployments?", options: ["A. All-at-once", "B. Blue/green with thorough testing", "C. In-place rolling", "D. Random selection"], answer: 1, explain: "Blue/green deployments provide the safest approach for critical deployments by maintaining two full environments." },
  { cat: "sdlc-automation", q: "What is a CodePipeline action provider?", options: ["A. A service that performs a specific task in a pipeline stage", "B. A CodeBuild configuration", "C. A deployment target", "D. An IAM role"], answer: 0, explain: "Action providers are AWS services integrated into CodePipeline stages, such as CodeBuild, CodeDeploy, or Lambda." },
  { cat: "sdlc-automation", q: "How do you specify environment variables in a CodeBuild project?", options: ["A. Only in buildspec.yml", "B. In the CodeBuild project definition or buildspec.yml", "C. Only in the AWS Console", "D. In CloudFormation templates"], answer: 1, explain: "Environment variables can be defined in the CodeBuild project settings or directly in the buildspec.yml file." },
  { cat: "sdlc-automation", q: "What is the CodeCommit repository access method using SSH?", options: ["A. SSH keys generated by AWS", "B. SSH keys uploaded to CodeCommit", "C. SSH keys stored in Systems Manager", "D. Only HTTP/HTTPS is supported"], answer: 1, explain: "CodeCommit supports SSH access using SSH public keys uploaded to your AWS account." },
  { cat: "sdlc-automation", q: "Which feature allows you to automatically rollback a deployment if health checks fail?", options: ["A. CodeDeploy rollback on failure", "B. CodePipeline rollback stage", "C. Lambda-based rollback", "D. Manual rollback only"], answer: 0, explain: "CodeDeploy can automatically rollback deployments if CloudWatch alarms indicate unhealthy instances." },
  { cat: "sdlc-automation", q: "What is the primary purpose of AWS CDK Stacks?", options: ["A. To define a collection of AWS resources", "B. To store deployment artifacts", "C. To manage IAM permissions", "D. To monitor infrastructure"], answer: 0, explain: "Stacks in CDK represent a collection of AWS resources that are deployed together." },
  { cat: "sdlc-automation", q: "How does CodePipeline handle source code changes?", options: ["A. It polls CodeCommit every minute", "B. It uses EventBridge rules to detect changes automatically", "C. Manual triggering only", "D. It integrates with CodeCommit webhooks"], answer: 1, explain: "CodePipeline can automatically detect source code changes using EventBridge rules without manual intervention." },
  { cat: "sdlc-automation", q: "What is a CodeBuild build environment?", options: ["A. An S3 bucket for artifacts", "B. The compute environment where build steps execute", "C. A CodeCommit repository", "D. A CloudFormation template"], answer: 1, explain: "A build environment is the managed compute resource where CodeBuild executes your build commands." },
  { cat: "sdlc-automation", q: "Which deployment configuration in CodeDeploy allows you to stop deployment if a threshold is exceeded?", options: ["A. MaximumPercent", "B. MinimumHealthyHosts", "C. TrafficControl", "D. AutoRollback"], answer: 1, explain: "MinimumHealthyHosts ensures a minimum number of instances remain healthy during deployment." },
  { cat: "sdlc-automation", q: "What is the benefit of using CodePipeline's approval stage?", options: ["A. Prevents unauthorized deployments", "B. Requires manual approval before deploying to production", "C. Automatically rejects bad code", "D. Reduces deployment cost"], answer: 1, explain: "Approval stages require explicit authorization before proceeding to sensitive stages like production deployment." },
  { cat: "sdlc-automation", q: "How do you trigger a CodePipeline from a GitHub repository?", options: ["A. Using CodePipeline GitHub connector", "B. Using CodeBuild GitHub integration", "C. Using EventBridge and CodePipeline", "D. Manual triggering only"], answer: 0, explain: "CodePipeline's GitHub connector automatically triggers the pipeline when code is pushed to a GitHub repository." },
  { cat: "sdlc-automation", q: "What does the 'BuildArtifacts' section in CodeBuild specify?", options: ["A. Where to store build output", "B. Dependencies to install", "C. Test configurations", "D. Source code location"], answer: 0, explain: "BuildArtifacts specifies which files from the build output should be stored in S3." },
  { cat: "sdlc-automation", q: "Which CDK construct is used to define a VPC?", options: ["A. Network", "B. Vpc", "C. VirtualNetwork", "D. CloudNetwork"], answer: 1, explain: "The Vpc construct in CDK allows you to define and configure Virtual Private Clouds." },
  { cat: "sdlc-automation", q: "What is the difference between in-place and blue/green deployments?", options: ["A. In-place is faster, blue/green is safer", "B. In-place updates existing instances, blue/green creates new ones", "C. Blue/green is only for Lambda", "D. In-place is for on-premises, blue/green for AWS"], answer: 1, explain: "In-place deployments update existing instances, while blue/green creates new instances and switches traffic." },
  { cat: "config-incident", q: "Which AWS service is used to monitor compliance with specific rules and configurations?", options: ["A. AWS CloudTrail", "B. AWS Config", "C. AWS Systems Manager", "D. AWS CloudWatch"], answer: 0, explain: "AWS Config continuously monitors resource configurations and compliance with specified rules." },
  { cat: "config-incident", q: "What is an AWS Config rule?", options: ["A. An IAM policy", "B. A compliance check for resource configurations", "C. A CloudTrail log entry", "D. A Systems Manager automation"], answer: 1, explain: "AWS Config rules are compliance checks that evaluate whether resources are configured correctly." },
  { cat: "config-incident", q: "Which service provides automated patching for EC2 instances?", options: ["A. AWS Config", "B. AWS Systems Manager Patch Manager", "C. AWS CodeDeploy", "D. AWS AppConfig"], answer: 1, explain: "Systems Manager Patch Manager automates the patching of EC2 instances and on-premises servers." },
  { cat: "config-incident", q: "What is AWS Systems Manager State Manager used for?", options: ["A. Managing EC2 instance states", "B. Defining and maintaining desired state configurations", "C. Tracking CloudTrail events", "D. Monitoring network state"], answer: 0, explain: "State Manager maintains consistent server configurations by defining and applying desired state configurations." },
  { cat: "config-incident", q: "Which feature allows you to automatically remediate Config rule violations?", options: ["A. Config Snapshots", "B. Config Rules evaluation", "C. Config Remediation Actions", "D. Config Aggregation"], answer: 2, explain: "Config Remediation Actions automatically fix violations of Config rules using predefined or custom remediation steps." },
  { cat: "config-incident", q: "What is AWS Systems Manager Automation used for?", options: ["A. Automating operational tasks", "B. Automating compliance checks", "C. Automating patch management", "D. Automating backup operations"], answer: 0, explain: "Systems Manager Automation creates and runs automation documents to perform operational tasks." },
  { cat: "config-incident", q: "Which service would you use to run commands on multiple EC2 instances at once?", options: ["A. Systems Manager Run Command", "B. Systems Manager State Manager", "C. AWS CodeDeploy", "D. AWS Lambda"], answer: 0, explain: "Systems Manager Run Command allows you to execute commands on multiple instances simultaneously." },
  { cat: "config-incident", q: "What does AWS CloudTrail log?", options: ["A. Application performance metrics", "B. AWS API calls and resource changes", "C. Network traffic", "D. System file changes"], answer: 1, explain: "CloudTrail logs all AWS API calls and actions taken by users, roles, and services." },
  { cat: "config-incident", q: "How long does CloudTrail store logs by default?", options: ["A. 30 days", "B. 90 days", "C. 1 year", "D. Indefinitely"], answer: 0, explain: "By default, CloudTrail retains event history for 90 days in the CloudTrail console." },
  { cat: "config-incident", q: "Which service helps track changes to AWS resources over time?", options: ["A. AWS Config Timeline", "B. AWS Config Configuration History", "C. AWS CloudTrail History", "D. AWS Systems Manager Change Log"], answer: 1, explain: "AWS Config Configuration History tracks configuration changes and allows point-in-time auditing." },
  { cat: "config-incident", q: "What is a Systems Manager Document?", options: ["A. A CloudTrail log entry", "B. A Config rule definition", "C. A set of steps for performing operational tasks", "D. An IAM policy document"], answer: 2, explain: "Systems Manager Documents define the steps and parameters for automations, patching, and running commands." },
  { cat: "config-incident", q: "Which Config rule type evaluates AWS resource configuration?", options: ["A. AWS managed rules only", "B. Custom Lambda rules only", "C. Both AWS managed and custom Lambda rules", "D. Webhook-based rules"], answer: 2, explain: "AWS Config supports both predefined AWS managed rules and custom Lambda-based rules." },
  { cat: "config-incident", q: "How do you create a custom Config rule?", options: ["A. Using AWS managed templates only", "B. Writing a Lambda function that evaluates resources", "C. Using CloudFormation only", "D. It's not possible"], answer: 1, explain: "Custom Config rules are created by writing Lambda functions that evaluate resource compliance." },
  { cat: "config-incident", q: "What is AWS Config Aggregator used for?", options: ["A. Aggregating CloudWatch metrics", "B. Aggregating Config data across multiple accounts and regions", "C. Aggregating CloudTrail logs", "D. Aggregating Systems Manager data"], answer: 1, explain: "Config Aggregator consolidates compliance data from multiple AWS accounts and regions." },
  { cat: "config-incident", q: "Which Systems Manager feature allows you to schedule patching windows?", options: ["A. Patch Manager", "B. Maintenance Windows", "C. Change Management", "D. State Manager"], answer: 0, explain: "Systems Manager Patch Manager allows you to define patching schedules and maintenance windows." },
  { cat: "config-incident", q: "What is the primary purpose of CloudTrail data events?", options: ["A. Monitoring API calls only", "B. Detailed logging of S3 object and Lambda function access", "C. Application performance monitoring", "D. Network activity logging"], answer: 1, explain: "CloudTrail data events provide detailed logs of S3 object-level and Lambda invocation activities." },
  { cat: "config-incident", q: "How can you ensure all EC2 instances are tagged according to standards?", options: ["A. Manual verification", "B. AWS Config rule with custom Lambda", "C. Systems Manager Automation", "D. CloudTrail monitoring"], answer: 1, explain: "You can create AWS Config rules to automatically check if EC2 instances have required tags." },
  { cat: "config-incident", q: "What is AWS Systems Manager Parameter Store used for?", options: ["A. Storing EC2 instance parameters", "B. Storing configuration values and secrets securely", "C. Storing CloudTrail logs", "D. Storing CloudFormation templates"], answer: 1, explain: "Parameter Store securely stores and retrieves configuration values, secrets, and application parameters." },
  { cat: "config-incident", q: "Which service would you use to manage compliance across multiple AWS accounts?", options: ["A. AWS Config Aggregator", "B. AWS Systems Manager", "C. AWS Organizations", "D. AWS CloudTrail"], answer: 0, explain: "AWS Config Aggregator provides compliance visibility across multiple accounts and regions." },
  { cat: "config-incident", q: "What is the purpose of CloudTrail log file validation?", options: ["A. To verify API call syntax", "B. To ensure CloudTrail logs haven't been modified", "C. To validate IAM permissions", "D. To check network connectivity"], answer: 1, explain: "Log file validation uses digital signatures to prove that CloudTrail logs haven't been tampered with." },
  { cat: "config-incident", q: "How does AWS Config detect non-compliant resources?", options: ["A. Real-time polling of resources", "B. By evaluating resources against Config rules", "C. Manual auditing only", "D. CloudTrail log analysis"], answer: 1, explain: "AWS Config continuously evaluates resources against rules and marks those that don't comply." },
  { cat: "config-incident", q: "Which Systems Manager feature helps with change management?", options: ["A. Change Calendar", "B. Change Manager", "C. Change Automation", "D. All of the above"], answer: 3, explain: "Systems Manager provides multiple change management features including Change Manager and Change Calendar." },
  { cat: "config-incident", q: "What is a Systems Manager Session?", options: ["A. A CloudTrail log entry", "B. An interactive shell connection to an EC2 instance", "C. A Config rule evaluation", "D. An automation execution"], answer: 1, explain: "Systems Manager Session Manager provides interactive shell access to EC2 instances without SSH keys." },
  { cat: "config-incident", q: "How can you automate response to Config rule violations?", options: ["A. Manual remediation only", "B. CloudWatch alarms with Lambda", "C. Config Remediation Actions", "D. It's not possible"], answer: 2, explain: "AWS Config Remediation Actions can automatically fix violations using predefined or custom remediation steps." },
  { cat: "config-incident", q: "What does the CloudTrail 'InsightEvents' feature detect?", options: ["A. Unusual API call patterns that may indicate issues", "B. Configuration changes only", "C. Network anomalies", "D. Application errors"], answer: 0, explain: "CloudTrail Insights automatically detects unusual API activity patterns that may indicate security threats." },
  { cat: "config-incident", q: "Which service would you use to track who accessed a specific S3 object?", options: ["A. CloudWatch Logs", "B. CloudTrail data events", "C. AWS Config", "D. Systems Manager"], answer: 1, explain: "CloudTrail data events log S3 object access with details about who accessed what and when." },
  { cat: "monitoring-logging", q: "What is the primary purpose of Amazon CloudWatch?", options: ["A. Storing application logs", "B. Monitoring and observability of AWS resources and applications", "C. Managing EC2 instances", "D. Automating deployments"], answer: 1, explain: "CloudWatch provides monitoring, logging, and alerting capabilities for AWS resources and applications." },
  { cat: "monitoring-logging", q: "Which CloudWatch feature collects application and system logs?", options: ["A. CloudWatch Metrics", "B. CloudWatch Logs", "C. CloudWatch Dashboards", "D. CloudWatch Events"], answer: 1, explain: "CloudWatch Logs collects, stores, and analyzes log data from applications and AWS services." },
  { cat: "monitoring-logging", q: "What is a CloudWatch alarm used for?", options: ["A. Storing logs", "B. Creating alerts based on metric thresholds", "C. Collecting metrics", "D. Displaying dashboards"], answer: 1, explain: "CloudWatch alarms monitor metrics and trigger actions when thresholds are breached." },
  { cat: "monitoring-logging", q: "Which AWS service provides distributed request tracing?", options: ["A. CloudWatch", "B. CloudTrail", "C. AWS X-Ray", "D. AWS Systems Manager"], answer: 2, explain: "AWS X-Ray traces requests across distributed applications, showing service interactions and performance." },
  { cat: "monitoring-logging", q: "What is AWS X-Ray service map used for?", options: ["A. Mapping EC2 instances", "B. Visualizing application components and their interactions", "C. Mapping network topology", "D. Showing API endpoints"], answer: 1, explain: "X-Ray service maps visualize how requests flow through application components." },
  { cat: "monitoring-logging", q: "Which CloudWatch feature allows you to visualize metrics in real-time?", options: ["A. CloudWatch Logs", "B. CloudWatch Metrics", "C. CloudWatch Dashboards", "D. CloudWatch Insights"], answer: 2, explain: "CloudWatch Dashboards display custom visualizations of metrics in real-time." },
  { cat: "monitoring-logging", q: "What is AWS CloudWatch Synthetics used for?", options: ["A. Monitoring synthetic transactions", "B. Synthetic data generation", "C. Automatic code synthesis", "D. Synthetic metric calculations"], answer: 0, explain: "CloudWatch Synthetics runs automated tests from different locations to monitor application availability." },
  { cat: "monitoring-logging", q: "Which service helps correlate logs from multiple sources?", options: ["A. CloudWatch Logs Insights", "B. CloudTrail", "C. X-Ray", "D. Systems Manager"], answer: 0, explain: "CloudWatch Logs Insights allows querying and analyzing logs from multiple applications and services." },
  { cat: "monitoring-logging", q: "What is an AWS EventBridge rule?", options: ["A. A CloudWatch alarm", "B. A routing rule for events to targets", "C. A Config rule", "D. A Systems Manager document"], answer: 1, explain: "EventBridge rules route events from sources to targets based on defined patterns." },
  { cat: "monitoring-logging", q: "Which CloudWatch feature detects anomalies in metrics automatically?", options: ["A. CloudWatch Alarms", "B. CloudWatch Anomaly Detector", "C. CloudWatch Insights", "D. CloudWatch Synthetics"], answer: 1, explain: "CloudWatch Anomaly Detector uses machine learning to detect unusual metric patterns." },
  { cat: "monitoring-logging", q: "How can you export CloudWatch Logs to S3?", options: ["A. Automatic daily export", "B. Using CloudWatch Logs subscription filters", "C. Using a Lambda function or Kinesis", "D. Manual export only"], answer: 2, explain: "CloudWatch Logs can be exported to S3 using subscription filters with Kinesis or Lambda." },
  { cat: "monitoring-logging", q: "What is a CloudWatch Logs group?", options: ["A. A collection of alarms", "B. A collection of related log streams", "C. A CloudFormation stack", "D. A Systems Manager document"], answer: 1, explain: "A log group is a collection of log streams with the same retention and permissions." },
  { cat: "monitoring-logging", q: "Which metric type represents the number of times an event occurred?", options: ["A. Counter", "B. Gauge", "C. Histogram", "D. Summary"], answer: 0, explain: "Counter metrics count the number of occurrences of an event." },
  { cat: "monitoring-logging", q: "What is the minimum resolution for CloudWatch Logs retention?", options: ["A. 1 day", "B. 7 days", "C. 1 month", "D. 1 year"], answer: 0, explain: "CloudWatch Logs can be retained for as little as 1 day up to indefinitely." },
  { cat: "monitoring-logging", q: "How does X-Ray help with application debugging?", options: ["A. Traces requests and shows service interactions", "B. Monitors application metrics", "C. Stores application logs", "D. Manages EC2 instances"], answer: 0, explain: "X-Ray provides end-to-end tracing showing where latency and errors occur in distributed applications." },
  { cat: "monitoring-logging", q: "What is a CloudWatch custom metric?", options: ["A. A predefined AWS metric", "B. A metric you create and publish", "C. A metric from a third-party service", "D. An automatically collected metric"], answer: 1, explain: "Custom metrics are application-specific metrics that you create and publish to CloudWatch." },
  { cat: "monitoring-logging", q: "Which EventBridge event source is most commonly used for AWS service integration?", options: ["A. Custom applications", "B. Partner events", "C. AWS services via CloudTrail", "D. Third-party SaaS applications"], answer: 2, explain: "EventBridge integrates with AWS services through CloudTrail events automatically." },
  { cat: "monitoring-logging", q: "How can you enable detailed monitoring for EC2 instances?", options: ["A. Automatically enabled by default", "B. Through CloudWatch agent installation", "C. Using EC2 detailed monitoring option", "D. Using Systems Manager"], answer: 2, explain: "EC2 detailed monitoring can be enabled to collect metrics at 1-minute intervals instead of 5-minute." },
  { cat: "monitoring-logging", q: "What is the purpose of CloudWatch Logs metric filters?", options: ["A. Filter log entries visually", "B. Extract metrics from log data", "C. Filter incoming logs", "D. Compress log data"], answer: 1, explain: "Metric filters parse log data and create CloudWatch metrics based on matching patterns." },
  { cat: "monitoring-logging", q: "Which X-Ray feature groups related requests for analysis?", options: ["A. Service map", "B. Trace segments", "C. Trace groups", "D. Service groups"], answer: 2, explain: "Trace groups allow you to organize and filter traces based on specific criteria." },
  { cat: "monitoring-logging", q: "How can you create a composite alarm in CloudWatch?", options: ["A. Using multiple metric alarms", "B. Using CloudWatch Composite Alarm feature", "C. Using EventBridge rules", "D. Using Systems Manager"], answer: 1, explain: "Composite alarms combine multiple alarms using AND/OR logic to create complex alerting rules." },
  { cat: "monitoring-logging", q: "What is the primary benefit of using CloudWatch Synthetics?", options: ["A. Reduced monitoring costs", "B. Proactive monitoring from multiple geographic locations", "C. Automatic log analysis", "D. Real-time metric collection"], answer: 1, explain: "Synthetics proactively test application endpoints from multiple regions to detect issues before users notice." },
  { cat: "monitoring-logging", q: "Which service would you use to monitor Lambda function performance?", options: ["A. CloudWatch Metrics and Logs", "B. AWS X-Ray", "C. CloudWatch Synthetics", "D. All of the above"], answer: 3, explain: "All three services provide different aspects of Lambda monitoring: metrics, tracing, and synthetic testing." },
  { cat: "monitoring-logging", q: "How does EventBridge improve upon CloudWatch Events?", options: ["A. EventBridge is the newer service with additional features", "B. They are the same service", "C. CloudWatch Events is more powerful", "D. EventBridge only works with EC2"], answer: 0, explain: "EventBridge is the evolution of CloudWatch Events with enhanced routing, filtering, and SaaS integration." },
  { cat: "monitoring-logging", q: "What is a CloudWatch Logs stream?", options: ["A. A continuous flow of log entries", "B. Real-time streaming to external systems", "C. A sequence of log events from a single source", "D. An automated log analysis"], answer: 2, explain: "A log stream is a sequence of log events from a single emitter like an EC2 instance." },
  { cat: "monitoring-logging", q: "Which alarm state indicates an alarm is not yet collecting enough data?", options: ["A. INSUFFICIENT_DATA", "B. PENDING", "C. UNKNOWN", "D. INITIALIZING"], answer: 0, explain: "INSUFFICIENT_DATA state indicates the alarm doesn't yet have enough data to evaluate the threshold." },
  { cat: "monitoring-logging", q: "How can you visualize X-Ray trace data?", options: ["A. CloudWatch Dashboards", "B. X-Ray Service Map and Timeline", "C. EventBridge visualizations", "D. Systems Manager dashboards"], answer: 1, explain: "X-Ray provides service maps and timeline views to visualize distributed trace data." },
  { cat: "policy-standards", q: "What is the primary purpose of resource tagging?", options: ["A. Improve EC2 performance", "B. Organize, identify, and manage resources", "C. Reduce AWS costs", "D. Increase security"], answer: 1, explain: "Tagging helps organize resources, track costs, enforce policies, and automate management." },
  { cat: "policy-standards", q: "Which service allows you to enforce tagging across all resources?", options: ["A. AWS Config", "B. AWS Organizations", "C. AWS Systems Manager", "D. AWS CloudFormation"], answer: 0, explain: "AWS Config rules can enforce tagging policies across resources and automatically remediate violations." },
  { cat: "policy-standards", q: "What is an AWS Organizations Service Control Policy (SCP)?", options: ["A. An IAM role policy", "B. A policy that restricts permissions across an organization", "C. A resource-based policy", "D. A bucket policy"], answer: 1, explain: "SCPs set maximum permissions for all accounts in an organization, acting as guardrails." },
  { cat: "policy-standards", q: "How do you implement a tagging policy in AWS Organizations?", options: ["A. Using SCPs only", "B. Using tag policies specific to Organizations", "C. Using IAM policies only", "D. Manual enforcement"], answer: 1, explain: "AWS Organizations provides tag policies that enforce consistent tagging across all accounts." },
  { cat: "policy-standards", q: "What is an IAM permission boundary?", options: ["A. A role that limits permissions", "B. The maximum permissions an identity can have", "C. A policy attached to resources", "D. A network boundary"], answer: 1, explain: "Permission boundaries define the maximum permissions a user or role can have." },
  { cat: "policy-standards", q: "Which tagging best practice involves using a consistent naming format?", options: ["A. Hierarchical tagging", "B. Standardized tag naming", "C. Organizational tagging", "D. Compliance tagging"], answer: 1, explain: "Standardized tagging uses consistent naming conventions across all resources." },
  { cat: "policy-standards", q: "How can you prevent expensive resources from being launched?", options: ["A. Using CloudWatch alarms", "B. Using SCPs or IAM policies", "C. Using Config rules", "D. Manual review only"], answer: 1, explain: "SCPs and IAM policies can restrict launching expensive instances based on type or size." },
  { cat: "policy-standards", q: "What is the purpose of AWS Cost Explorer?", options: ["A. Analyzing resource usage and costs", "B. Predicting future costs", "C. Optimizing spending", "D. All of the above"], answer: 3, explain: "Cost Explorer provides cost analysis, forecasting, and optimization recommendations." },
  { cat: "policy-standards", q: "Which feature helps identify unused resources?", options: ["A. AWS Cost Explorer", "B. AWS Trusted Advisor", "C. AWS Compute Optimizer", "D. All of the above"], answer: 3, explain: "Multiple AWS services help identify unused and inefficient resources." },
  { cat: "policy-standards", q: "What is a resource governance policy?", options: ["A. A policy that controls resource access", "B. A policy that enforces standards for resource management", "C. An IAM policy", "D. A tag policy"], answer: 1, explain: "Resource governance policies enforce standards for how resources are created and managed." },
  { cat: "policy-standards", q: "How can you enforce encryption across all resources?", options: ["A. Using IAM policies", "B. Using SCPs and Config rules", "C. Using CloudFormation only", "D. Manual enforcement"], answer: 1, explain: "SCPs can restrict unencrypted operations, and Config rules can detect unencrypted resources." },
  { cat: "policy-standards", q: "What is the purpose of AWS Trusted Advisor?", options: ["A. Provides security recommendations", "B. Analyzes AWS accounts against best practices", "C. Monitors application performance", "D. Manages user access"], answer: 1, explain: "Trusted Advisor checks AWS accounts against security, performance, cost, and compliance best practices." },
  { cat: "policy-standards", q: "Which Organizations feature groups accounts into logical units?", options: ["A. Organization Units (OUs)", "B. Account groups", "C. Organization clusters", "D. Account containers"], answer: 0, explain: "Organization Units (OUs) group accounts within an organization for policy application." },
  { cat: "policy-standards", q: "How do you apply an SCP to a specific account?", options: ["A. Directly to the account", "B. To the OU containing the account", "C. To the organization root", "D. SCPs can't target specific accounts"], answer: 1, explain: "SCPs are attached to OUs or the root, affecting all accounts in that organizational unit." },
  { cat: "policy-standards", q: "What is the purpose of compliance baselines?", options: ["A. Establishing minimum security standards", "B. Tracking compliance violations", "C. Automating remediation", "D. Monitoring compliance metrics"], answer: 0, explain: "Compliance baselines define the minimum security and operational standards required." },
  { cat: "policy-standards", q: "Which service helps automate compliance checking?", options: ["A. AWS Config", "B. AWS Organizations", "C. AWS Systems Manager", "D. AWS CloudTrail"], answer: 0, explain: "AWS Config provides automated compliance checking against defined rules." },
  { cat: "policy-standards", q: "How can you enforce consistent security groups across accounts?", options: ["A. Using SCPs", "B. Using CloudFormation StackSets", "C. Using Config rules", "D. Manual enforcement"], answer: 2, explain: "AWS Config rules can detect non-compliant security groups and trigger remediation." },
  { cat: "policy-standards", q: "What is AWS Glue used for?", options: ["A. Tagging resources", "B. ETL and data catalog services", "C. Enforcing policies", "D. Monitoring resources"], answer: 1, explain: "AWS Glue provides ETL capabilities and a data catalog for data integration." },
  { cat: "policy-standards", q: "Which feature allows you to track resource ownership?", options: ["A. Resource tagging with owner tags", "B. CloudTrail logging", "C. Config rules", "D. Systems Manager"], answer: 0, explain: "Owner tags applied consistently help identify who is responsible for each resource." },
  { cat: "policy-standards", q: "How do you implement a chargeback model?", options: ["A. Using Cost Allocation Tags and Cost Explorer", "B. Using billing alerts", "C. Using CloudWatch alarms", "D. Manual tracking"], answer: 0, explain: "Cost Allocation Tags enable tracking costs by department or project for chargeback." },
  { cat: "policy-standards", q: "What is the benefit of implementing resource naming standards?", options: ["A. Automatic resource discovery", "B. Improved resource identification and management", "C. Enhanced security", "D. Reduced costs"], answer: 1, explain: "Naming standards improve resource identification, making management and automation easier." },
  { cat: "policy-standards", q: "Which AWS service helps optimize Reserved Instance usage?", options: ["A. Cost Explorer", "B. Compute Optimizer", "C. Trusted Advisor", "D. All of the above"], answer: 3, explain: "Multiple services provide recommendations for optimizing instance reservations and purchasing." },
  { cat: "incident-event-response", q: "What is the primary benefit of Lambda-based auto-remediation?", options: ["A. Faster response to security issues", "B. Automatic fixing of non-compliant resources", "C. Reduced manual intervention", "D. All of the above"], answer: 3, explain: "Lambda functions can automatically remediate issues, reducing MTTR and manual work." },
  { cat: "incident-event-response", q: "Which AWS service is used for event-driven remediation?", options: ["A. CloudWatch Events", "B. EventBridge", "C. Systems Manager", "D. Lambda only"], answer: 1, explain: "EventBridge routes events to remediation targets, enabling automated response to incidents." },
  { cat: "incident-event-response", q: "What is AWS Systems Manager OpsCenter used for?", options: ["A. Centralized incident management", "B. Resource monitoring", "C. Log aggregation", "D. Cost tracking"], answer: 0, explain: "OpsCenter provides a central location to manage operational items and incidents." },
  { cat: "incident-event-response", q: "How does SNS help with incident alerting?", options: ["A. Sends notifications to multiple recipients", "B. Aggregates logs", "C. Monitors resources", "D. Performs remediation"], answer: 0, explain: "SNS delivers incident alerts to email, SMS, and other endpoints for rapid notification." },
  { cat: "incident-event-response", q: "What is SQS used for in incident response?", options: ["A. Decoupling alert processing from response actions", "B. Storing incident logs", "C. Monitoring incidents", "D. Routing events"], answer: 0, explain: "SQS allows incident response systems to decouple alert reception from processing." },
  { cat: "incident-event-response", q: "Which runbook feature enables automatic execution?", options: ["A. Manual runbooks", "B. Automation documents with automatic execution", "C. CloudFormation templates", "D. Lambda functions only"], answer: 1, explain: "Systems Manager Automation documents can be configured to execute automatically on specific triggers." },
  { cat: "incident-event-response", q: "What is chaos engineering?", options: ["A. Testing system reliability through intentional failures", "B. Randomizing system configurations", "C. Chaos Monkey for AWS", "D. Automated testing"], answer: 0, explain: "Chaos engineering intentionally introduces failures to test system resilience and identify weaknesses." },
  { cat: "incident-event-response", q: "Which AWS service facilitates chaos engineering experiments?", options: ["A. AWS FIS (Fault Injection Simulator)", "B. AWS CloudFormation", "C. AWS Systems Manager", "D. AWS Lambda"], answer: 0, explain: "AWS FIS provides controlled fault injection testing for resilience engineering." },
  { cat: "incident-event-response", q: "What is a disaster recovery strategy that maintains a hot standby?", options: ["A. RPO/RTO", "B. Warm standby", "C. Hot standby/active-active", "D. Cold standby"], answer: 2, explain: "Hot standby maintains duplicate systems that are constantly synchronized for instant failover." },
  { cat: "incident-event-response", q: "Which disaster recovery approach has the lowest RTO?", options: ["A. Cold standby", "B. Warm standby", "C. Hot standby", "D. RPO-based"], answer: 2, explain: "Hot standby/active-active configurations provide the lowest Recovery Time Objective." },
  { cat: "incident-event-response", q: "What is RPO in disaster recovery?", options: ["A. Recovery Point Objective - acceptable data loss", "B. Recovery Time Objective", "C. Resource Protection Organization", "D. Redundancy Protocol Overview"], answer: 0, explain: "RPO defines the maximum acceptable amount of data loss in a disaster recovery scenario." },
  { cat: "incident-event-response", q: "How can you automate disaster recovery failover?", options: ["A. Using Route 53 health checks with automatic failover", "B. Using Lambda-triggered failover", "C. Using Systems Manager Automation", "D. All of the above"], answer: 3, explain: "Multiple AWS services can automate failover using health checks and automation documents." },
  { cat: "incident-event-response", q: "What is the purpose of a runbook in incident response?", options: ["A. Document incident procedures", "B. Automate incident response", "C. Both document and automate", "D. Log incidents"], answer: 2, explain: "Runbooks document procedures and Systems Manager can automate execution via automation documents." },
  { cat: "incident-event-response", q: "Which metric measures how quickly an incident is resolved?", options: ["A. MTTR (Mean Time To Recovery)", "B. MTTD (Mean Time To Detect)", "C. RPO", "D. RTO"], answer: 0, explain: "MTTR measures the average time to restore service after an incident is detected." },
  { cat: "incident-event-response", q: "How can you reduce MTTD (Mean Time To Detect)?", options: ["A. Better monitoring and alerting", "B. Faster incident response", "C. Comprehensive logging", "D. Both A and C"], answer: 3, explain: "Improved monitoring, alerting, and logging all reduce the time to detect incidents." },
  { cat: "incident-event-response", q: "What is a cross-region replication strategy?", options: ["A. Duplicating resources across regions", "B. Using Route 53 for DNS failover", "C. Synchronizing data across regions", "D. All of the above"], answer: 3, explain: "Cross-region replication involves duplicating resources and data across regions for disaster recovery." },
  { cat: "incident-event-response", q: "Which service enables continuous backup automation?", options: ["A. AWS Backup", "B. AWS DLM (Data Lifecycle Manager)", "C. RDS automated backups", "D. All of the above"], answer: 3, explain: "Multiple services provide automated backup capabilities for disaster recovery." },
  { cat: "incident-event-response", q: "What is the purpose of incident communication templates?", options: ["A. Standardize incident notifications", "B. Reduce response time", "C. Improve clarity and consistency", "D. All of the above"], answer: 3, explain: "Standardized communication templates ensure clear and consistent incident notifications." },
  { cat: "incident-event-response", q: "How does Systems Manager OpsItems help with incident tracking?", options: ["A. Centralizes operational issues", "B. Tracks incident resolution", "C. Provides audit trail", "D. All of the above"], answer: 3, explain: "OpsItems provide centralized tracking and resolution of operational issues with audit trails." },
  { cat: "incident-event-response", q: "Which automated response reduces the impact of security incidents?", options: ["A. Automatic isolation of affected resources", "B. Automatic credential rotation", "C. Automatic logging", "D. All of the above"], answer: 3, explain: "Comprehensive automated responses minimize incident impact across multiple dimensions." },
  { cat: "incident-event-response", q: "What is the benefit of automated failover testing?", options: ["A. Identifies failover gaps", "B. Ensures RTO/RPO compliance", "C. Builds team confidence", "D. All of the above"], answer: 3, explain: "Regular automated failover testing validates disaster recovery capabilities and team readiness." },
  { cat: "incident-event-response", q: "How can Lambda be used in incident response?", options: ["A. Perform automated remediation", "B. Process and analyze alerts", "C. Trigger remediation workflows", "D. All of the above"], answer: 3, explain: "Lambda functions are core to automated incident detection, processing, and remediation." },
  { cat: "incident-event-response", q: "What is the purpose of incident severity levels?", options: ["A. Prioritize response", "B. Allocate resources appropriately", "C. Track incident patterns", "D. Both A and B"], answer: 3, explain: "Severity levels help prioritize incidents and allocate appropriate response resources." },
  { cat: "incident-event-response", q: "Which service helps coordinate distributed incident response?", options: ["A. Systems Manager OpsCenter", "B. SNS/SQS", "C. EventBridge", "D. All of the above"], answer: 3, explain: "Multiple services coordinate incident response across distributed teams and systems." },
  { cat: "incident-event-response", q: "What is a failure domain in architecture design?", options: ["A. A region that failed", "B. An isolated subsystem to contain failures", "C. A network segment", "D. A security boundary"], answer: 1, explain: "Failure domains isolate subsystems to prevent cascading failures across the entire system." },
  { cat: "incident-event-response", q: "How does automatic scaling contribute to disaster recovery?", options: ["A. Handles increased traffic automatically", "B. Maintains availability during failures", "C. Reduces manual intervention", "D. All of the above"], answer: 3, explain: "Auto scaling maintains service availability and handles increased traffic without manual intervention." },
  { cat: "high-availability", q: "What is the primary benefit of multi-region architecture?", options: ["A. Reduced latency globally", "B. Disaster recovery and failover capability", "C. Improved reliability", "D. All of the above"], answer: 3, explain: "Multi-region architectures provide latency reduction, disaster recovery, and improved reliability." },
  { cat: "high-availability", q: "Which Route 53 routing policy distributes traffic based on latency?", options: ["A. Simple routing", "B. Latency-based routing", "C. Geolocation routing", "D. Weighted routing"], answer: 1, explain: "Latency-based routing directs users to the lowest-latency endpoint." },
  { cat: "high-availability", q: "What is a Route 53 health check used for?", options: ["A. Check application health", "B. Verify endpoint availability before routing traffic", "C. Monitor resource status", "D. All of the above"], answer: 3, explain: "Health checks verify endpoint availability and enable automatic failover routing." },
  { cat: "high-availability", q: "Which ELB feature monitors instance health?", options: ["A. ELB health checks", "B. CloudWatch alarms", "C. Systems Manager Patch Manager", "D. Route 53 health checks"], answer: 0, explain: "ELB health checks continuously verify instance health and remove unhealthy instances from rotation." },
  { cat: "high-availability", q: "How does RDS Multi-AZ improve availability?", options: ["A. Synchronously replicates to standby instance", "B. Automatic failover on primary failure", "C. Both A and B", "D. Only manual failover"], answer: 2, explain: "RDS Multi-AZ provides synchronous replication and automatic failover for high availability." },
  { cat: "high-availability", q: "What is RDS read replica?", options: ["A. A read-only copy of the database", "B. A backup copy", "C. An automatic failover", "D. A database clone"], answer: 0, explain: "Read replicas are asynchronous copies of RDS databases used for read scaling." },
  { cat: "high-availability", q: "Which cross-region replication method is synchronous?", options: ["A. S3 cross-region replication", "B. RDS read replicas", "C. Asynchronous replication", "D. Synchronous replication is not available cross-region"], answer: 3, explain: "Cross-region replication is typically asynchronous; synchronous is within regions via Multi-AZ." },
  { cat: "high-availability", q: "What is the purpose of backup automation?", options: ["A. Ensure data recovery capability", "B. Meet compliance requirements", "C. Test disaster recovery", "D. All of the above"], answer: 3, explain: "Automated backups ensure data protection, compliance, and support disaster recovery testing." },
  { cat: "high-availability", q: "Which AWS service provides managed backup across accounts and regions?", options: ["A. AWS Backup", "B. RDS automated backups", "C. S3 versioning", "D. CloudFormation"], answer: 0, explain: "AWS Backup provides centralized, automated backup management across AWS services and accounts." },
  { cat: "high-availability", q: "What is failover testing?", options: ["A. Testing automatic failover mechanisms", "B. Validating disaster recovery readiness", "C. Identifying single points of failure", "D. All of the above"], answer: 3, explain: "Failover testing validates disaster recovery mechanisms and identifies potential issues." },
  { cat: "high-availability", q: "How does Application Load Balancer (ALB) improve availability?", options: ["A. Distributes traffic across instances", "B. Health checks and removes unhealthy targets", "C. Provides automatic failover", "D. Both A and B"], answer: 3, explain: "ALB distributes traffic and performs health checks to maintain availability." },
  { cat: "high-availability", q: "What is active-passive failover?", options: ["A. One active, one passive standby", "B. Automatic traffic switching", "C. Requires manual intervention", "D. Both A and B"], answer: 3, explain: "Active-passive requires one active instance and a passive standby; failover can be automatic or manual." },
  { cat: "high-availability", q: "What is active-active failover?", options: ["A. Multiple active instances", "B. Traffic to all instances simultaneously", "C. No single point of failure", "D. All of the above"], answer: 3, explain: "Active-active architectures distribute traffic across multiple active instances with no single point of failure." },
  { cat: "high-availability", q: "Which architectural pattern uses multiple availability zones?", options: ["A. Single-AZ", "B. Multi-AZ", "C. Cross-region", "D. Distributed"], answer: 1, explain: "Multi-AZ architectures spread resources across availability zones for fault tolerance." },
  { cat: "high-availability", q: "How can you ensure database availability across AZs?", options: ["A. RDS Multi-AZ", "B. Aurora with multiple replicas", "C. DynamoDB with Global Tables", "D. All of the above"], answer: 3, explain: "Multiple services provide cross-AZ replication for database high availability." },
  { cat: "high-availability", q: "What is the benefit of Aurora Global Database?", options: ["A. Read replicas in multiple regions", "B. Cross-region failover", "C. Sub-second replication lag", "D. All of the above"], answer: 3, explain: "Aurora Global Database provides low-latency read replicas with fast failover capability." },
  { cat: "high-availability", q: "Which DynamoDB feature provides global high availability?", options: ["A. DynamoDB Streams", "B. DynamoDB Global Tables", "C. DynamoDB backups", "D. DynamoDB DAX"], answer: 1, explain: "DynamoDB Global Tables replicate data across regions with sub-second synchronization." },
  { cat: "high-availability", q: "What is S3 cross-region replication?", options: ["A. Automatic backup to another region", "B. Asynchronous replication of objects to another region", "C. Multi-region availability", "D. Versioning across regions"], answer: 1, explain: "S3 CRR asynchronously replicates objects to another region for disaster recovery." },
  { cat: "high-availability", q: "How does Route 53 failover routing improve availability?", options: ["A. Automatic failover to secondary resource", "B. Health check-based routing", "C. Reduces manual intervention", "D. All of the above"], answer: 3, explain: "Failover routing automatically redirects traffic to secondary resources on primary failure." },
  { cat: "high-availability", q: "What is a circuit breaker pattern?", options: ["A. Prevents cascading failures", "B. Temporarily halts requests to failing services", "C. Automatic recovery mechanism", "D. All of the above"], answer: 3, explain: "Circuit breakers prevent cascading failures by stopping requests to failing services temporarily." },
  { cat: "high-availability", q: "Which metric measures system availability?", options: ["A. RTO (Recovery Time Objective)", "B. RPO (Recovery Point Objective)", "C. Uptime percentage (99.99%)", "D. All of the above"], answer: 2, explain: "Uptime percentage (e.g., 99.99% availability) measures system availability." },
  { cat: "high-availability", q: "How can you achieve five-nines (99.999%) availability?", options: ["A. Single-region architecture", "B. Multi-region, multi-AZ with failover", "C. Distributed globally with no single points of failure", "D. Both B and C"], answer: 3, explain: "Achieving five-nines requires redundancy across multiple regions and availability zones." },
  { cat: "high-availability", q: "What is the purpose of a load balancer in a HA architecture?", options: ["A. Distribute traffic", "B. Detect and handle instance failures", "C. Maintain service availability", "D. All of the above"], answer: 3, explain: "Load balancers distribute traffic and handle failure detection for high availability." },
  { cat: "high-availability", q: "Which auto scaling trigger helps maintain availability?", options: ["A. CPU utilization", "B. Memory utilization", "C. Custom metrics", "D. All of the above"], answer: 3, explain: "Auto scaling can trigger on various metrics to maintain availability and performance." },
  { cat: "high-availability", q: "How does CloudFront improve application availability?", options: ["A. Caches content globally", "B. Provides DDoS protection", "C. Reduces latency", "D. All of the above"], answer: 3, explain: "CloudFront edge locations cache content and provide resilience against regional outages." },
  { cat: "high-availability", q: "What is the benefit of database read replicas for availability?", options: ["A. Improves read performance", "B. Provides failover capability", "C. Distributes load", "D. All of the above"], answer: 3, explain: "Read replicas improve performance and can be promoted to primary for failover." },
  { cat: "high-availability", q: "How can you ensure application data consistency across regions?", options: ["A. Synchronous replication", "B. Asynchronous replication with eventual consistency", "C. Data locality strategies", "D. All of the above"], answer: 3, explain: "Different approaches balance consistency, latency, and availability based on requirements." },
  { cat: "high-availability", q: "What is the advantage of using managed services for HA?", options: ["A. Built-in redundancy", "B. Automatic failover", "C. Reduced operational burden", "D. All of the above"], answer: 3, explain: "Managed services like RDS and DynamoDB provide built-in HA features." },
  { cat: "high-availability", q: "Which deployment pattern ensures zero downtime updates?", options: ["A. Blue-green deployment", "B. Canary deployment", "C. Rolling deployment", "D. All of the above"], answer: 3, explain: "All three patterns can achieve zero-downtime updates with proper implementation." },
  { cat: "sdlc-automation", q: "In a CodeDeploy AppSpec file, which lifecycle hook runs before deregistering instances from a load balancer during deployment?", options: ["A. BeforeBlockTraffic", "B. BeforeInstall", "C. ApplicationStart", "D. BeforeAllowTraffic"], answer: 0, explain: "BeforeBlockTraffic is the lifecycle hook that runs before instances are deregistered from load balancers, allowing graceful connection draining." },
  { cat: "sdlc-automation", q: "What is the primary purpose of using CDK Pipelines in infrastructure as code?", options: ["A. Self-mutating pipeline that updates itself when pipeline code changes", "B. Compile CloudFormation templates", "C. Deploy Lambda functions only", "D. Manage IAM roles"], answer: 0, explain: "CDK Pipelines enable self-mutating CI/CD pipelines defined in code, allowing infrastructure changes to update the pipeline automatically." },
  { cat: "sdlc-automation", q: "In CodePipeline cross-account deployments, where should the S3 artifact bucket be located?", options: ["A. Source account, with bucket policy allowing cross-account access", "B. Target account only", "C. Both accounts with replication", "D. Central artifact account only"], answer: 0, explain: "The S3 artifact bucket can be in the source account with appropriate cross-account bucket policies granting the target account read access." },
  { cat: "sdlc-automation", q: "What is the role of CodeDeploy lifecycle event hooks in deployment validation?", options: ["A. Execute custom scripts at specific deployment stages for validation and health checks", "B. Compile source code", "C. Store artifacts", "D. Monitor CloudWatch metrics"], answer: 0, explain: "Lifecycle hooks allow running validation scripts during deployment, such as health checks and smoke tests." },
  { cat: "sdlc-automation", q: "In buildspec.yml, what does the 'cache' section allow you to do?", options: ["A. Store dependencies locally to speed up subsequent builds", "B. Configure build output", "C. Define build phases", "D. Set environment variables"], answer: 0, explain: "The cache section specifies which directories to cache (e.g., /root/.m2 for Maven, node_modules for npm) between builds." },
  { cat: "config-incident", q: "What is the primary benefit of AWS Config Aggregator for multi-account environments?", options: ["A. Centralize Config data from multiple accounts and regions into a single aggregator account", "B. Aggregate CloudWatch metrics", "C. Combine VPC Flow Logs", "D. Merge CloudTrail events"], answer: 0, explain: "Config Aggregator collects and centralizes AWS Config data across multiple member accounts and regions." },
  { cat: "config-incident", q: "In an Auto-remediation workflow using Config and Lambda, what information is passed to the Lambda function?", options: ["A. Non-compliant resource ID and rule name through EventBridge event", "B. Only the rule name", "C. Full AWS account data", "D. Manual configuration only"], answer: 0, explain: "EventBridge sends details including the non-compliant resource, configuration, and rule name for remediation Lambda to use." },
  { cat: "config-incident", q: "What is the primary purpose of Systems Manager Automation runbooks in incident response?", options: ["A. Automate remediation workflows by orchestrating AWS API calls", "B. Monitor resource metrics", "C. Store configuration data", "D. Generate CloudFormation templates"], answer: 0, explain: "Automation runbooks define repeatable, automated response procedures that orchestrate multiple AWS service API calls." },
  { cat: "config-incident", q: "How can AWS Config trigger Systems Manager Automation for auto-remediation?", options: ["A. Config Remediation action invokes SSM Automation runbook on non-compliance", "B. Manual trigger through AWS Console", "C. CloudWatch Events only", "D. SNS notifications only"], answer: 0, explain: "Config rules can be configured to automatically invoke SSM Automation runbooks as remediation actions." },
  { cat: "config-incident", q: "What prevents idempotency issues in Lambda-based Config auto-remediation?", options: ["A. Lambda function should check if remediation is already applied before re-applying", "B. Config prevents duplicate events", "C. Automatic deduplication by AWS", "D. Not a concern in auto-remediation"], answer: 0, explain: "Remediation Lambda functions should include idempotency checks to avoid cascading changes from repeated executions." },
  { cat: "monitoring-logging", q: "What is CloudWatch Contributor Insights used for?", options: ["A. Identify top contributors in logs (IPs, users, resources) consuming the most traffic or errors", "B. Monitor EC2 CPU", "C. Track cost allocations", "D. Generate dashboards"], answer: 0, explain: "Contributor Insights analyzes logs to identify top talkers and resource consumers by analyzing VPC Flow Logs or custom logs." },
  { cat: "monitoring-logging", q: "What is the Embedded Metrics Format (EMF) in CloudWatch?", options: ["A. JSON structure in application logs that embeds high-cardinality metrics bypassing PutMetricData API limits", "B. Dashboard template format", "C. VPC Flow Log format", "D. CloudTrail event format"], answer: 0, explain: "EMF allows publishing metrics directly through logs with high-cardinality dimensions without hitting CloudWatch API throttles." },
  { cat: "monitoring-logging", q: "How does cross-account CloudWatch observability benefit multi-account architectures?", options: ["A. Monitoring account can view metrics and logs from source accounts without data replication", "B. Requires copying all data to monitoring account", "C. Only supports single account", "D. Manual data collection required"], answer: 0, explain: "Cross-account observability provides centralized visibility without duplicating data, reducing storage and network costs." },
  { cat: "monitoring-logging", q: "What AWS service provides visual mapping of application dependencies and performance?", options: ["A. AWS X-Ray ServiceLens, combining metrics and traces", "B. CloudWatch dashboards only", "C. VPC Flow Logs", "D. CloudTrail"], answer: 0, explain: "ServiceLens displays service topology and integrates CloudWatch metrics with X-Ray trace data for complete visibility." },
  { cat: "policy-standards", q: "What is the most effective approach to enforce required tags across all resources in AWS?", options: ["A. Config 'required-tags' rule with auto-remediation Lambda to add missing tags", "B. Manual tag verification", "C. IAM policies only", "D. CloudTrail monitoring"], answer: 0, explain: "Combine Config rules to detect non-compliance with Lambda remediation for automatic tag enforcement." },
  { cat: "policy-standards", q: "Why use cost allocation tags in AWS organizations?", options: ["A. Track and allocate AWS spending to specific departments, projects, or cost centers for chargeback", "B. Security compliance only", "C. Performance monitoring", "D. Access control"], answer: 0, explain: "Cost allocation tags enable accurate cost tracking and chargeback models in multi-team environments." },
  { cat: "incident-event-response", q: "What is the primary advantage of using Service Control Policies (SCP) for DevOps governance?", options: ["A. Deny specific AWS actions organization-wide, creating guardrails across all accounts", "B. Grant user permissions", "C. Monitor API usage", "D. Create AWS resources"], answer: 0, explain: "SCPs are maximum permission boundaries that deny actions across all organization accounts, regardless of IAM policies." },
  { cat: "sdlc-automation", q: "Which service allows you to define and execute build steps using YAML-based buildspec files?", options: ["A. AWS CodeBuild", "B. AWS CodePipeline", "C. AWS CodeDeploy", "D. AWS CodeCommit"], answer: 1, explain: "CodeBuild executes build commands defined in buildspec.yml files, compiling code and running tests." },
  { cat: "config-incident", q: "What permissions must a remediation Lambda function have?", options: ["A. Read-only Config permissions", "B. Permissions to call service APIs needed to fix the resource", "C. Full admin access", "D. No permissions needed"], answer: 2, explain: "Remediation Lambda requires IAM permissions to call the specific service APIs needed to remediate each resource type." },
  { cat: "config-incident", q: "How should auto-remediation Lambda functions be designed for safety?", options: ["A. Always attempt to fix", "B. Include idempotency checks and rate limiting", "C. Skip validation", "D. Fix everything immediately"], answer: 2, explain: "Remediation Lambda should be idempotent, rate-limited, and include validation to prevent cascading changes." },
  { cat: "config-incident", q: "What should you log for Config remediation audit trail?", options: ["A. Lambda print statements only", "B. CloudWatch Logs and Config snapshots showing before/after changes", "C. Manual log files", "D. Nothing required"], answer: 2, explain: "Best practice: log Lambda execution in CloudWatch Logs and compare Config snapshots to track changes." },
  { cat: "monitoring-logging", q: "Which log format does Contributor Insights support?", options: ["A. JSON format only", "B. VPC Flow Logs and custom space-delimited logs with named fields", "C. Application logs only", "D. CloudTrail format only"], answer: 2, explain: "Contributor Insights supports VPC Flow Logs and custom space-delimited log formats with field names." },
  { cat: "monitoring-logging", q: "How do you create a Contributor Insights rule for custom applications?", options: ["A. AWS Console only", "B. Using CloudWatch Logs Insights query syntax or CLI", "C. Lambda function only", "D. Not supported"], answer: 2, explain: "Create rules via AWS Console, CLI with JSON definitions, or CloudWatch Logs Insights query syntax." },
  { cat: "monitoring-logging", q: "What is the main advantage of Embedded Metrics Format?", options: ["A. Reduces logging volume", "B. Publish high-cardinality metrics bypassing CloudWatch API rate limits", "C. Faster query performance", "D. Automatic log aggregation"], answer: 2, explain: "EMF allows applications to publish metrics with many unique dimension values without hitting PutMetricData API limits." },
  { cat: "monitoring-logging", q: "What must be configured for cross-account CloudWatch observability?", options: ["A. Copy all data to monitoring account", "B. Link source accounts and grant observability permissions", "C. CloudFormation stack", "D. Not required"], answer: 2, explain: "Setup requires linking source accounts to monitoring account and granting observability IAM permissions." },
  { cat: "monitoring-logging", q: "Can CloudWatch Logs Insights query logs from multiple accounts?", options: ["A. No, one account only", "B. Yes, with cross-account observability enabled", "C. Yes, requires data replication", "D. Only with CloudTrail"], answer: 2, explain: "With cross-account observability enabled, Logs Insights can query logs across linked accounts from the monitoring account." },
  { cat: "monitoring-logging", q: "What data sources does AWS X-Ray ServiceLens integrate?", options: ["A. CloudWatch metrics only", "B. CloudWatch metrics and X-Ray trace data", "C. Logs only", "D. CloudTrail only"], answer: 2, explain: "ServiceLens combines CloudWatch metrics with X-Ray traces to show complete service topology and performance." },
  { cat: "monitoring-logging", q: "How does ServiceLens help identify performance bottlenecks?", options: ["A. CPU metrics only", "B. Visual topology showing service latency and error rates", "C. Log analysis only", "D. Manual investigation"], answer: 2, explain: "ServiceLens displays service relationships with latency, error rates, and trace data for quick bottleneck identification." },
  { cat: "incident-event-response", q: "What is AWS EventBridge Scheduler?", options: ["A. Monitors EC2 schedules", "B. Managed service for scheduling one-time or recurring task invocations", "C. CloudWatch alarm scheduler", "D. Auto-scaling scheduler"], answer: 2, explain: "EventBridge Scheduler enables scheduling Lambda, SNS, SQS, and other targets to run at specific times or intervals." },
  { cat: "incident-event-response", q: "How do you define recurring schedules in EventBridge Scheduler?", options: ["A. CloudWatch Events format", "B. Using cron expressions (e.g., 'cron(0 12 * * ? *)') or rate expressions", "C. Lambda schedule syntax", "D. Plain English"], answer: 2, explain: "EventBridge Scheduler supports standard cron expressions and rate expressions for flexible scheduling." },
  { cat: "incident-event-response", q: "What advantage does EventBridge Scheduler provide over CloudWatch Events?", options: ["A. Better performance", "B. Native timezone support and enhanced scheduling flexibility", "C. Lower cost", "D. No advantages"], answer: 2, explain: "EventBridge Scheduler offers timezone-aware scheduling, up to 3-hour timezone offset support, and improved flexibility." },
  { cat: "incident-event-response", q: "Can a single EventBridge Scheduler rule invoke multiple targets?", options: ["A. No, one target only", "B. Yes, through routing rules", "C. Yes, multiple targets can be defined", "D. Requires separate rules"], answer: 2, explain: "A single schedule can invoke multiple targets (Lambda, SNS, SQS) to run in parallel." },
  { cat: "incident-event-response", q: "How should failed EventBridge Scheduler invocations be handled?", options: ["A. Automatic retry by default", "B. Configure Dead Letter Queue (DLQ) in SQS for analysis", "C. Manual retry required", "D. Failed events are discarded"], answer: 2, explain: "Configure an SQS DLQ to capture failed invocations for troubleshooting and manual remediation." },
  { cat: "incident-event-response", q: "What is AWS Systems Manager Incident Manager?", options: ["A. Tracks configuration changes", "B. Coordinates incident response with automation, escalation, and collaboration", "C. Monitors EC2 instances", "D. Manages patches"], answer: 2, explain: "Incident Manager provides on-call management, response automation, and integrated incident coordination." },
  { cat: "incident-event-response", q: "What does an Incident Manager Response Plan define?", options: ["A. CloudFormation template", "B. Escalation paths, severity levels, and remediation runbooks", "C. CloudWatch dashboard", "D. SNS configuration"], answer: 2, explain: "Response Plans specify escalation chains, incident severity levels, on-call contacts, and auto-remediation runbooks." },
  { cat: "incident-event-response", q: "How does Incident Manager escalate incidents?", options: ["A. Always notifies all on-call personnel", "B. Based on severity and Response Plan configuration", "C. Requires manual escalation", "D. CloudWatch alarms only"], answer: 2, explain: "Incident Manager escalates based on incident severity levels and Response Plan escalation rules." },
  { cat: "incident-event-response", q: "Can CloudWatch alarms automatically create Incident Manager incidents?", options: ["A. No, manual creation only", "B. Yes, through EventBridge integration", "C. Yes, with native CloudWatch integration", "D. Requires SNS"], answer: 2, explain: "CloudWatch can send alarms through EventBridge to automatically create Incident Manager incidents." },
  { cat: "incident-event-response", q: "What collaboration tools does Incident Manager support?", options: ["A. Email only", "B. Slack, Microsoft Teams, and AWS-native chat", "C. SMS only", "D. Internal dashboards"], answer: 2, explain: "Incident Manager integrates with Slack, Teams, and native AWS Chat for real-time team collaboration." },
  { cat: "incident-event-response", q: "What is AWS Fault Injection Simulator (FIS)?", options: ["A. Security scanning tool", "B. Service for safely running chaos experiments on AWS infrastructure", "C. Disaster recovery tool", "D. Performance testing"], answer: 2, explain: "FIS enables controlled chaos engineering to test system resilience and identify weaknesses." },
  { cat: "incident-event-response", q: "What types of faults can FIS inject into infrastructure?", options: ["A. EC2 termination only", "B. EC2 termination, CPU stress, network latency, EBS failures, RDS failures", "C. Database only", "D. Networking only"], answer: 2, explain: "FIS supports EC2 termination, CPU/memory stress, network partition, EBS latency, RDS failure injection, and more." },
  { cat: "incident-event-response", q: "What is the best practice for running FIS experiments in production?", options: ["A. Run during peak hours", "B. Start with small blast radius, monitor systems, plan rollback", "C. Run without monitoring", "D. Not recommended"], answer: 2, explain: "Best practice: start with canary blast radius, have rollback procedures, comprehensive monitoring, then gradually increase scope." },
  { cat: "incident-event-response", q: "What is a stop condition in FIS experiments?", options: ["A. Time limit", "B. CloudWatch alarm that auto-stops if threshold exceeded", "C. Manual stop button", "D. CPU limit"], answer: 2, explain: "Stop conditions are CloudWatch alarms that automatically halt experiments if metrics exceed critical thresholds." },
  { cat: "incident-event-response", q: "How can FIS integrate with Incident Manager?", options: ["A. Not possible", "B. FIS can trigger Response Plans during chaos experiments", "C. Manual integration", "D. SNS only"], answer: 2, explain: "FIS can trigger Incident Manager Response Plans to test incident response procedures during chaos testing." },
  { cat: "incident-event-response", q: "How can Auto Scaling policies respond to custom CloudWatch alarms?", options: ["A. Target Tracking only", "B. Step Scaling policies can be based on custom alarm states", "C. Only CPU and network", "D. Not supported"], answer: 2, explain: "Target Tracking and Step Scaling policies can use custom CloudWatch metrics and alarms for scaling decisions." },
  { cat: "incident-event-response", q: "What is the benefit of Target Tracking scaling over Step Scaling?", options: ["A. Step Scaling is simpler", "B. Target Tracking automatically adjusts to maintain target metric value", "C. Lower cost", "D. No difference"], answer: 2, explain: "Target Tracking simplifies scaling by automatically adjusting ASG size to maintain your specified metric target." },
  { cat: "incident-event-response", q: "What is the purpose of cooldown period in Auto Scaling?", options: ["A. Minimum time between scaling actions", "B. Maximum time for scale-up", "C. CloudWatch check interval", "D. Backup time"], answer: 2, explain: "Cooldown prevents rapid successive scaling, allowing time for changes to take effect before evaluating metrics again." },
  { cat: "incident-event-response", q: "How can predictive scaling benefit Auto Scaling Groups?", options: ["A. Manual forecasting only", "B. ML-based load prediction to proactively scale before demand increases", "C. Fixed schedule only", "D. Not available"], answer: 2, explain: "Predictive Scaling uses machine learning on historical patterns to forecast load and scale proactively." },
  { cat: "high-availability", q: "What is Route 53 Application Recovery Controller?", options: ["A. DNS failover only", "B. Managed multi-region active-active failover with RTO/RPO < 1 minute", "C. CloudFront distribution", "D. Application load balancer"], answer: 2, explain: "ARC provides cross-region failover with health checks and instant recovery for near-zero downtime." },
  { cat: "high-availability", q: "What advantage does ARC provide over standard Route 53?", options: ["A. Lower cost", "B. Faster failover (seconds vs minutes) independent of DNS TTL", "C. Automatic scaling", "D. DNS resolution only"], answer: 2, explain: "ARC enables near-instantaneous cross-region failover without DNS TTL delays through independent regional health checks." },
  { cat: "high-availability", q: "What does ARC readiness check verify?", options: ["A. DNS resolution", "B. Applications and resources are ready before traffic shift", "C. Database replication only", "D. CloudWatch metrics"], answer: 2, explain: "Readiness checks verify that applications, databases, and resources are ready to receive traffic before shifting." },
  { cat: "high-availability", q: "Can Route 53 ARC support active-active multi-region deployments?", options: ["A. No, one region only", "B. Yes, with traffic distributed across regions", "C. Yes, manual switching only", "D. Requires separate services"], answer: 2, explain: "ARC supports active-active deployments with traffic distributed across multiple regions." },
  { cat: "high-availability", q: "What monitoring should be integrated with ARC?", options: ["A. CloudWatch metrics only", "B. Custom health checks, CloudWatch alarms, and application metrics", "C. Logs only", "D. CloudTrail only"], answer: 2, explain: "ARC should integrate with comprehensive monitoring: health checks, infrastructure metrics, and application-level indicators." },
  { cat: "high-availability", q: "What is Amazon Aurora Global Database?", options: ["A. Single region multi-AZ", "B. Multi-region read-only replicas with cross-region failover", "C. RDS snapshot", "D. Read replica only"], answer: 2, explain: "Aurora Global Database replicates data across regions with near-zero lag and enables cross-region failover." },
  { cat: "high-availability", q: "How are write operations handled in Aurora Global Database?", options: ["A. Distributed writes", "B. Writes only to primary region, secondary is read-only until promoted", "C. Both regions can write", "D. No writes allowed"], answer: 2, explain: "Primary region accepts all writes; secondary regions are read-only until promoted during failover." },
  { cat: "high-availability", q: "What RPO does Aurora Global Database provide?", options: ["A. Minutes", "B. Hours", "C. Near-zero with typical < 1 second lag", "D. Varies by region"], answer: 2, explain: "Aurora Global Database provides near-zero RPO with typical replication lag under 1 second." },
  { cat: "high-availability", q: "What is active-active multi-region deployment?", options: ["A. One region serves traffic only", "B. Traffic distributed to multiple regions with bidirectional sync", "C. Standby only", "D. Manual failover"], answer: 2, explain: "Active-active means multiple regions simultaneously serve traffic with synchronized data." },
  { cat: "high-availability", q: "What is a key challenge in active-active deployments?", options: ["A. Higher cost only", "B. Data consistency and conflict resolution", "C. Latency only", "D. All of the above"], answer: 2, explain: "Active-active requires handling concurrent writes, potential conflicts, and ensuring eventual consistency." },
  { cat: "high-availability", q: "Which database supports true active-active multi-region?", options: ["A. RDS with replication", "B. Aurora Global Database", "C. DynamoDB Global Tables with bidirectional sync", "D. Requires custom code"], answer: 2, explain: "DynamoDB Global Tables support true active-active with automatic conflict resolution." },
  { cat: "high-availability", q: "How should traffic be routed in active-active deployment?", options: ["A. Geolocation routing only", "B. Latency-based or weighted routing", "C. Equal distribution only", "D. Manual"], answer: 2, explain: "Use latency-based routing to minimize user latency or weighted routing for controlled distribution." },
  { cat: "high-availability", q: "What is DynamoDB Global Tables?", options: ["A. Backups only", "B. Multi-region, multi-master replication with local writes", "C. Snapshots", "D. Streams"], answer: 2, explain: "Global Tables replicate DynamoDB tables across regions with bidirectional sync and local write capability." },
  { cat: "high-availability", q: "What consistency model do DynamoDB Global Tables provide?", options: ["A. Strong consistency", "B. Eventual consistency with last-writer-wins conflict resolution", "C. No consistency", "D. Tunable"], answer: 2, explain: "Global Tables provide eventual consistency with automatic conflict resolution using timestamp-based last-writer-wins." },
  { cat: "high-availability", q: "How does DynamoDB resolve concurrent writes in Global Tables?", options: ["A. Rejects second write", "B. Last-writer-wins based on high-resolution timestamp", "C. Manual resolution", "D. Always consistent"], answer: 2, explain: "DynamoDB Global Tables automatically apply last-writer-wins using high-resolution timestamps." },
  { cat: "incident-event-response", q: "What best practices prevent cascading Auto Scaling failures?", options: ["A. Larger cooldown periods and health checks", "B. Multiple scaling metrics with staggered thresholds", "C. Reserved capacity", "D. All of the above"], answer: 3, explain: "Best practice: reasonable cooldown, health checks, multiple metrics, and staggered thresholds prevent thrashing." },
  { cat: "incident-event-response", q: "What factors should be monitored during FIS chaos experiments?", options: ["A. CPU only", "B. Error rates, latency, and resource metrics", "C. Logs only", "D. Manual observation"], answer: 3, explain: "Comprehensive monitoring during experiments: application metrics, infrastructure health, error rates, and response times." },
  { cat: "incident-event-response", q: "How should you validate system resilience after FIS experiments?", options: ["A. No validation needed", "B. Manual testing only", "C. Review metrics, alarms, and auto-remediation effectiveness", "D. Schedule follow-up tests"], answer: 3, explain: "Post-experiment review: analyze metrics, confirm alarms fired properly, verify remediation worked, document findings." },
  { cat: "incident-event-response", q: "What are the key components of incident response automation?", options: ["A. Manual escalation only", "B. Automated detection, escalation, remediation, and team collaboration", "C. Alerts only", "D. Dashboards"], answer: 3, explain: "Effective automation: CloudWatch/Config detection, instant escalation, auto-remediation runbooks, and team notification." },
  { cat: "incident-event-response", q: "How should you integrate multiple monitoring and remediation systems?", options: ["A. Separate manual processes", "B. EventBridge rules connecting CloudWatch, Config, Incident Manager, and remediation", "C. Dashboards only", "D. Not recommended"], answer: 3, explain: "Best practice: EventBridge orchestrates detection from CloudWatch/Config, triggers Incident Manager, and invokes remediation." },
  { cat: "incident-event-response", q: "What metrics indicate incident response effectiveness?", options: ["A. Response time only", "B. MTTD, MTTR, automation percentage, false alert rate", "C. Downtime only", "D. Cost only"], answer: 3, explain: "Key metrics: Mean Time To Detect, Mean Time To Resolve, automation percentage, and false positive rate." },
  { cat: "incident-event-response", q: "How should you test incident response automation safely?", options: ["A. Only in production", "B. FIS experiments, staging environment chaos, and response plan dry-runs", "C. Never test", "D. Manual only"], answer: 3, explain: "Comprehensive testing: staging environment experiments, response plan walkthroughs, and controlled production chaos." },
  { cat: "incident-event-response", q: "What role does EventBridge play in comprehensive incident response?", options: ["A. Logging only", "B. Connects monitoring, remediation, incident management, and notification systems", "C. Dashboards", "D. Cost tracking"], answer: 3, explain: "EventBridge is the orchestration layer connecting CloudWatch, Config, Lambda, Incident Manager, and SNS." },
  { cat: "high-availability", q: "What multi-region strategy ensures lowest latency for global users?", options: ["A. Single region only", "B. Active-active with Route 53 latency-based routing", "C. Passive standby", "D. Manual failover"], answer: 3, explain: "Active-active with latency-based routing automatically directs users to nearest healthy region." },
  { cat: "high-availability", q: "How should you handle data synchronization in active-active deployments?", options: ["A. Manual sync", "B. No sync needed", "C. Use database-level multi-master replication with conflict resolution", "D. Single region only"], answer: 3, explain: "Active-active requires automatic multi-master replication with strong conflict resolution (DynamoDB Global Tables, Aurora Global)." },
  { cat: "high-availability", q: "What is the optimal Aurora multi-region strategy for near-zero RPO and RTO?", options: ["A. Single region only", "B. Global Database with read-only secondary promoted for failover", "C. Backups only", "D. Manual replication"], answer: 3, explain: "Aurora Global Database: primary region handles writes, secondary provides read scale and instant failover promotion." },
  { cat: "high-availability", q: "How can you ensure zero-downtime deployments across regions?", options: ["A. Deploy sequentially to each region", "B. Blue-green or canary deployments with Route 53 traffic shifting", "C. Single deployment", "D. Manual region switching"], answer: 3, explain: "Blue-green deployments across regions with Route 53 traffic management enable zero-downtime updates." },
  { cat: "high-availability", q: "What should Route 53 Application Recovery Controller monitor?", options: ["A. DNS only", "B. Application health, resource readiness, and data replication status", "C. CPU metrics", "D. Cost only"], answer: 3, explain: "ARC should monitor application-level health, resource readiness, and cross-region replication lag." },
  { cat: "high-availability", q: "How does DynamoDB Global Tables ensure write consistency?", options: ["A. No consistency", "B. Strongly consistent", "C. Last-writer-wins with per-item versioning and timestamp comparison", "D. Manual resolution"], answer: 3, explain: "DynamoDB uses high-resolution timestamps per item to determine write order and apply last-writer-wins." },
  { cat: "high-availability", q: "What is the relationship between RTO and failover automation?", options: ["A. No relationship", "B. Automated failover reduces RTO by eliminating manual intervention delay", "C. Manual only", "D. Increases RTO"], answer: 3, explain: "Automated failover dramatically reduces RTO: manual failover might take 15-30 minutes; automated can be <1 minute." },
  { cat: "high-availability", q: "How should you validate multi-region failover procedures?", options: ["A. Never test", "B. Chaos experiments with FIS, automated failover drills, and recovery metrics verification", "C. Manual only", "D. Production only"], answer: 3, explain: "Comprehensive validation: FIS multi-region experiments, automated failover drills, and RTO/RPO measurement." },
  { cat: "high-availability", q: "What is the benefit of cross-region read replicas?", options: ["A. Write performance only", "B. Reduced latency for read-heavy workloads and failover capacity", "C. Cost reduction", "D. Security only"], answer: 3, explain: "Cross-region replicas improve read performance locally and serve as failover targets." },
  { cat: "high-availability", q: "How should auto-scaling be configured for multi-region deployments?", options: ["A. Single region only", "B. Independent scaling per region plus cross-region load monitoring", "C. Disabled", "D. Manual only"], answer: 3, explain: "Each region scales independently based on local load; monitor aggregate traffic to plan cross-region capacity." },
  { cat: "high-availability", q: "What monitoring indicates multi-region replication health?", options: ["A. CPU only", "B. Replication lag, data consistency, and cross-region network latency", "C. Memory", "D. Disk space"], answer: 3, explain: "Monitor replication lag, data validation checks, and network connectivity between regions." },
  { cat: "high-availability", q: "How can you implement graceful degradation across regions?", options: ["A. All or nothing", "B. Progressive failover: local region, nearby region, then far region", "C. Manual switching", "D. No degradation"], answer: 3, explain: "Graceful degradation: fail to nearest healthy region first, then progressively to farther regions as needed." },
  { cat: "high-availability", q: "What is a service-level objective (SLO) for multi-region availability?", options: ["A. No SLO needed", "B. Target metrics: uptime %, RTO < X minutes, RPO < Y seconds", "C. Best effort", "D. Infrastructure only"], answer: 3, explain: "Multi-region SLOs should define uptime targets, RTO/RPO objectives, and failover success metrics." },
  { cat: "high-availability", q: "How should you design for data consistency in eventual consistency systems?", options: ["A. Strong consistency only", "B. Design applications for eventual consistency with idempotent operations", "C. No design needed", "D. Accept data loss"], answer: 3, explain: "Eventual consistency requires: idempotent operations, conflict-free replicated data types (CRDTs), and application-level reconciliation." },
  { cat: "high-availability", q: "What disaster recovery testing should include multi-region scenarios?", options: ["A. Single region only", "B. Regional failure, data center loss, and complete region unavailability", "C. No testing", "D. Infrastructure only"], answer: 3, explain: "Test scenarios: single region failure, multi-region failures, network partitions, and data center outages." }
];
